function BabylonViewer({ id }: { id: number }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current!;
    const engine = new BABYLON.Engine(canvas, true);
    const scene = new BABYLON.Scene(engine);

    const camera = new BABYLON.ArcRotateCamera(
      "cam",
      Math.PI / 2,
      Math.PI / 2,
      10,
      BABYLON.Vector3.Zero(),
      scene
    );
    camera.attachControl(canvas, true);

    new BABYLON.HemisphericLight("light", new BABYLON.Vector3(1, 1, 0), scene);

    axios.get("http://localhost:8080/api/complex-shapes").then(res => {
      const shape = res.data.find((x: any) => x.id === id);

      const mesh1 = createMesh(scene, shape.shape1, -shape.offset - 1);
      const mesh2 = createMesh(scene, shape.shape2, shape.offset + 1);

      const csg1 = BABYLON.CSG.FromMesh(mesh1);
      const csg2 = BABYLON.CSG.FromMesh(mesh2);

      let result;

      if (shape.operation === "ADD") result = csg1.union(csg2);
      else if (shape.operation === "SUBTRACT") result = csg1.subtract(csg2);
      else result = csg1.intersect(csg2);

      const finalMesh = result.toMesh("result", null, scene);

      mesh1.dispose();
      mesh2.dispose();
    });

    function createMesh(scene: BABYLON.Scene, shape: any, x: number) {
      let mesh;

      const size = shape.relativeSize || 1;

      if (shape.shape === "Box") {
        mesh = BABYLON.MeshBuilder.CreateBox(shape.label, { size }, scene);
      } else if (shape.shape === "Sphere") {
        mesh = BABYLON.MeshBuilder.CreateSphere(shape.label, { diameter: size }, scene);
      } else {
        mesh = BABYLON.MeshBuilder.CreateCylinder(shape.label, { height: size }, scene);
      }

      mesh.position.x = x;
      return mesh;
    }

    engine.runRenderLoop(() => scene.render());

    return () => engine.dispose();
  }, [id]);

  return <canvas ref={canvasRef} style={{ width: "100%", height: "500px" }} />;
}

export default BabylonViewer;
